// PayWorkerNow is the resolver for the payWorkerNow field.
func (r *mutationResolver) PayWorkerNow(ctx context.Context, input gqlmodel.PayWorkerNowInput) (*driversettlement.Settlement, error) {
	authCtx, err := r.requirePermission(ctx, permission.ResourceDriverSettlement, permission.OpApprove)
	if err != nil {
		return nil, err
	}
	workerID, err := pulid.MustParse(input.WorkerID)
	if err != nil {
		return nil, errortypes.NewValidationError("workerId", errortypes.ErrInvalid, "Invalid worker")
	}
	eventIDs := make([]pulid.ID, 0, len(input.PayEventIds))
	for _, raw := range input.PayEventIds {
		eventID, idErr := pulid.MustParse(raw)
		if idErr != nil {
			return nil, errortypes.NewValidationError(
				"payEventIds",
				errortypes.ErrInvalid,
				"Invalid pay event",
			)
		}
		eventIDs = append(eventIDs, eventID)
	}
	req := &driversettlementservice.PayWorkerNowRequest{
		TenantInfo:    tenantInfo(authCtx),
		WorkerID:      workerID,
		PayEventIDs:   eventIDs,
		PaymentMethod: input.PaymentMethod,
	}
	if input.ApplyRecurring != nil {
		req.ApplyRecurring = *input.ApplyRecurring
	}
	if input.PaymentReference != nil {
		req.PaymentReference = *input.PaymentReference
	}
	return r.driverSettlementService.PayWorkerNow(ctx, req, actorutil.FromAuthContext(authCtx))
}

